func (o *TeamDriver) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "Driver":
		rel, ok := retrieved.(*Driver)
		if !ok {
			return fmt.Errorf("teamDriver cannot load %T as %q", retrieved, name)
		}

		o.R.Driver = rel
		o.R.Loaded.Driver = true

		if rel != nil {
			rel.R.TeamDrivers = TeamDriverSlice{o}
		}
		return nil
	case "Team":
		rel, ok := retrieved.(*Team)
		if !ok {
			return fmt.Errorf("teamDriver cannot load %T as %q", retrieved, name)
		}

		o.R.Team = rel
		o.R.Loaded.Team = true

		if rel != nil {
			rel.R.TeamDrivers = TeamDriverSlice{o}
		}
		return nil
	default:
		return fmt.Errorf("teamDriver has no relationship %q", name)
	}
}

type teamDriverPreloader struct {
	Driver func(...psql.PreloadOption) psql.Preloader
	Team   func(...psql.PreloadOption) psql.Preloader
}

func buildTeamDriverPreloader() teamDriverPreloader {
	return teamDriverPreloader{
		Driver: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Driver, DriverSlice](psql.PreloadRel{
				Name: "Driver",
				Sides: []psql.PreloadSide{
					{
						From:        TeamDrivers,
						To:          Drivers,
						FromColumns: []string{"driver_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, Drivers.Columns.Names(), opts...)
		},
		Team: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Team, TeamSlice](psql.PreloadRel{
				Name: "Team",
				Sides: []psql.PreloadSide{
					{
						From:        TeamDrivers,
						To:          Teams,
						FromColumns: []string{"team_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, Teams.Columns.Names(), opts...)
		},
	}
}

type teamDriverThenLoader[Q orm.Loadable] struct {
	Driver func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	Team   func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildTeamDriverThenLoader[Q orm.Loadable]() teamDriverThenLoader[Q] {
	type DriverLoadInterface interface {
		LoadDriver(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type TeamLoadInterface interface {
		LoadTeam(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return teamDriverThenLoader[Q]{
		Driver: thenLoadBuilder[Q](
			"Driver",
			func(ctx context.Context, exec bob.Executor, retrieved DriverLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadDriver(ctx, exec, mods...)
			},
		),
		Team: thenLoadBuilder[Q](
			"Team",
			func(ctx context.Context, exec bob.Executor, retrieved TeamLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadTeam(ctx, exec, mods...)
			},
		),
	}
}

// LoadDriver loads the teamDriver's Driver into the .R struct
func (o *TeamDriver) LoadDriver(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Driver = nil
	o.R.Loaded.Driver = false

	related, err := o.Driver(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.TeamDrivers = TeamDriverSlice{o}

	o.R.Driver = related
	o.R.Loaded.Driver = true
	return nil
}

// LoadDriver loads the teamDriver's Driver into the .R struct
func (os TeamDriverSlice) LoadDriver(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	drivers, err := os.Driver(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.Driver = nil
		o.R.Loaded.Driver = true
	}
	// O(N+M) stitch via a map keyed by the join column (key -> []parent; was O(N*M)).
	teamDriverByKey := make(map[int32][]*TeamDriver, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}

		teamDriverByKey[o.DriverID] = append(teamDriverByKey[o.DriverID], o)
	}

	for _, rel := range drivers {

		owners, ok := teamDriverByKey[rel.ID]
		if !ok {
			continue
		}

		for _, o := range owners {

			// to-one: keep only the first matching child (matches the previous break)
			if o.R.Driver != nil {
				continue
			}

			rel.R.TeamDrivers = append(rel.R.TeamDrivers, o)

			o.R.Driver = rel

		}
	}

	return nil
}

