type teamDriverJoins[Q dialect.Joinable] struct {
	typ    string
	Driver modAs[Q, driverColumns]
	Team   modAs[Q, teamColumns]
}

func (j teamDriverJoins[Q]) aliasedAs(alias string) teamDriverJoins[Q] {
	return buildTeamDriverJoins[Q](buildTeamDriverColumns(alias), j.typ)
}

func buildTeamDriverJoins[Q dialect.Joinable](cols teamDriverColumns, typ string) teamDriverJoins[Q] {
	return teamDriverJoins[Q]{
		typ: typ,
		Driver: modAs[Q, driverColumns]{
			c: Drivers.Columns,
			f: func(to driverColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Drivers.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.DriverID),
					))
				}

				return mods
			},
		},
		Team: modAs[Q, teamColumns]{
			c: Teams.Columns,
			f: func(to teamColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Teams.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.TeamID),
					))
				}

				return mods
			},
		},
	}
}
